import{_ as s,C as l,o as a,c as i,H as e,w as n,k as _,a as c,Q as O}from"./chunks/framework.e9710eb2.js";const p=JSON.parse('{"title":"MySQL升级5.7,sql语句报错解决","description":"","frontmatter":{},"headers":[],"relativePath":"pages/note/back/mysql-note/mysql-note-2.md","filePath":"pages/note/back/mysql-note/mysql-note-2.md","lastUpdated":1700105199000}'),r={name:"pages/note/back/mysql-note/mysql-note-2.md"},E=_("h1",{id:"mysql升级5-7-sql语句报错解决",tabindex:"-1"},[c("MySQL升级5.7,sql语句报错解决 "),_("a",{class:"header-anchor",href:"#mysql升级5-7-sql语句报错解决","aria-label":'Permalink to "MySQL升级5.7,sql语句报错解决"'},"​")],-1),d=O('<blockquote><p>MySQL升级5.7之后经常会出现这种错误：[Err] 1055 - Expression #1 of ORDER BY clause is not in GROUP BY clause and contains nonaggregated column &#39;information_schema.PROFILING.SEQ&#39;,虽然不影响SQL执行，但感觉不好</p></blockquote><ol><li>查询一下配置看看具体的情况</li></ol><ul><li><code>select @@sql_mode;</code></li><li>ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION <ul><li>其中ONLY_FULL_GROUP_BY就是造成这个错误的罪魁祸首</li><li>对于group by聚合操作,如果在select中的列没有在group by中出现,那么这个SQL是不合法的,因为列不在group by从句中,所以设置了sql_mode=only_full_group_by的数据库,在使用group by时就会报错</li></ul></li></ul><ol start="2"><li>找到MySQL的配置文件</li></ol><ul><li>Windows系统配置文件为安装MySQL目录下的my.ini文件，linux系统是/etc/my.cnf文件，查询sql_mode字段，我并没有在配置文件中找到这个关键字,所以我手动添加进去 <ul><li><code>sql_mode = STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION</code><ul><li>一定要添加在[mysqld]配置内，这样添加完后重启mysql才会生效</li></ul></li></ul></li></ul><ol start="3"><li>重启mysql</li></ol><ul><li><code>service mysqld restart;</code></li></ul><ol start="4"><li>刷新页面报错信息消失成功解决，再次连接上数据库查看sql_mode配置</li></ol><ul><li><code>select @@sql_mode;</code><ul><li>STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION</li></ul></li></ul>',9);function N(R,T,m,u,S,y){const o=l("Valine"),t=l("ClientOnly");return a(),i("div",null,[E,e(t,null,{default:n(()=>[e(o)]),_:1}),d])}const q=s(r,[["render",N]]);export{p as __pageData,q as default};
